    let trapezoidCount = 0;
    for (const [slope, count] of slopeMap.entries()) {
        // For each pair of points with the same slope, count the number of other pairs with the same slope
        // That forms a trapezoid with at least one pair of parallel sides
        trapezoidCount += (count * (count - 1)) / 2;
    }

    return trapezoidCount;
}

