        if dx == 0 && dy == 0 {
            return std::f64::NAN; // same point
        }
        if dx == 0 {
            return std::f64::INFINITY; // vertical line
        }
        dy as f64 / dx as f64
    }

    // Count all pairs of points and store their slopes
    for i in 0..n {
        for j in i + 1..n {
            let slope = get_slope(&points[i], &points[j]);
            if slope.is_nan() {
                continue;
            }
            let key = slope.to_string();
            *slope_map.entry(key).or_insert(0) += 1;
        }
    }

    // Calculate the number of trapezoids
    let mut trapezoid_count = 0;
    for (_, count) in slope_map {
        trapezoid_count += (count * (count - 1)) / 2;
    }

    trapezoid_count
}
